);

CREATE TABLE users (
  id SERIAL PRIMARY KEY,
  username VARCHAR(256) UNIQUE NOT NULL,
  password VARCHAR(256) NOT NULL,
  full_name TEXT NOT NULL,
  phone VARCHAR(256),
  university VARCHAR(256),
  major VARCHAR(256),
  year INTEGER,
